comments.body:
Bug is here in InstCombineAddSub.cpp

```
  {                                                                              
    // To ensure we can save instructions we need to ensure that we consume both 
    // LHS/RHS (i.e they have a `not`).                                          
    bool ConsumesLHS, ConsumesRHS;                                               
    if (isFreeToInvert(LHS, LHS->hasOneUse(), ConsumesLHS) && ConsumesLHS &&     
        isFreeToInvert(RHS, RHS->hasOneUse(), ConsumesRHS) && ConsumesRHS) {     
      Value *NotLHS = getFreelyInverted(LHS, LHS->hasOneUse(), &Builder);        
      Value *NotRHS = getFreelyInverted(RHS, RHS->hasOneUse(), &Builder);        
      assert(NotLHS != nullptr && NotRHS != nullptr &&                           
             "isFreeToInvert desynced with getFreelyInverted");                  
      Value *LHSPlusRHS = Builder.CreateAdd(NotLHS, NotRHS);                     
      return BinaryOperator::CreateSub(ConstantInt::get(RHS->getType(), -2),     
                                       LHSPlusRHS);                              
    }                                                                            
  }
```

The `ConstantInt::get(RHS->getType(), -2)` needs to be `ConstantInt::getSigned(RHS->getType(), -2)`

patch:
commit 7f1c8fc25a4dbf34ed479e0f5c4e85f32d98b8f2
Author: Craig Topper <craig.topper@sifive.com>
Date:   Wed Dec 27 12:27:12 2023 -0800

    [InstCombine] Use ConstantInt::getSigned to sign extend -2 for large types. (#76464)

    Using ContantInt::get will zero extend.

    Fixes #76441

diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 719a2678fc18..556fde37efeb 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1685,8 +1685,8 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
       assert(NotLHS != nullptr && NotRHS != nullptr &&
              "isFreeToInvert desynced with getFreelyInverted");
       Value *LHSPlusRHS = Builder.CreateAdd(NotLHS, NotRHS);
-      return BinaryOperator::CreateSub(ConstantInt::get(RHS->getType(), -2),
-                                       LHSPlusRHS);
+      return BinaryOperator::CreateSub(
+          ConstantInt::getSigned(RHS->getType(), -2), LHSPlusRHS);
     }
   }
